UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['A metes-and-bounds description traces the perimeter of one closed parcel: caption -> POC/POB -> body of courses -> monuments -> closing call -> area -> certification.','''Metes'' are the measured courses (bearing + distance); ''bounds'' are the monuments/adjoiners that limit the tract.','In Texas the caption recites the original GLO survey and abstract number because there is no PLSS grid.','A description that does not mathematically close is legally defective.']::text[], learning_objectives=ARRAY['Identify the standard components of a metes-and-bounds description in order: caption, point of commencement/beginning, body of courses, monument and closing calls, area, and certification.','Explain why a description must close to form a single, unambiguous parcel.','Recognize Texas-specific caption conventions (original GLO survey + abstract number) and the governing standard in 22 TAC §138.91.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='ac63566a-d49c-47db-97c5-cc9186fdee08';
DELETE FROM lesson_blocks WHERE lesson_id='ac63566a-d49c-47db-97c5-cc9186fdee08';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['The POB is the corner where the perimeter run begins and ends; the POC is an optional well-known reference used to reach the POB.','By Texas convention the POB ties to an original GLO survey corner so the parcel can be relocated independently of the surveyor''s own work.','Monuments are set or found at the POB and documented under 22 TAC Sec. 138.87.']::text[], learning_objectives=ARRAY['Distinguish the Point of Commencement (POC) from the Point of Beginning (POB) and explain when each is used.','Explain why the POB is tied back to a corner of the original GLO survey/abstract in Texas practice.','Describe how monuments at the POB are established or referenced under 22 TAC Sec. 138.87 (Monumentation).']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='5c4cda74-f4e2-45d8-bfdd-373702f28d14';
DELETE FROM lesson_blocks WHERE lesson_id='5c4cda74-f4e2-45d8-bfdd-373702f28d14';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['A course = direction (bearing) + length (distance); bearings must reference a stated basis of bearing.','Azimuth is measured clockwise from north 0-360 deg; a quadrant bearing is 0-90 deg off the N-S line; back-azimuth = azimuth +/- 180 deg.','Latitude = distance x cos(bearing angle); Departure = distance x sin(bearing angle).','1 vara = 33 1/3 in = 2.7778 ft (multiply varas by 2.7778, or divide by 0.36).']::text[], learning_objectives=ARRAY['Read and write a course call as a quadrant bearing plus a distance, with a stated basis of bearing.','Convert between bearings, azimuths, and back-azimuths.','Compute the latitude and departure of a course and use them to check closure.','Convert vara distances to feet for historical Texas field notes.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='89312e01-b753-4286-ac10-c7096c77357e';
DELETE FROM lesson_blocks WHERE lesson_id='89312e01-b753-4286-ac10-c7096c77357e';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['Natural monuments are permanent natural features (rivers, creeks, ridgelines, established trees); artificial monuments are surveyor-made (iron rods, pipes, concrete monuments, fences).','Monuments outrank course and distance because they are more reliable evidence of where the line was actually run.','22 TAC Sec. 138.91(e) requires stating which monuments were found and which were placed, plus other record-dignity monuments relied upon.']::text[], learning_objectives=ARRAY['Distinguish natural monuments from artificial monuments and give Texas examples of each.','Explain why monuments control over course and distance in a boundary conflict.','Apply 22 TAC Sec. 138.91(e) requirements to document found versus placed monuments.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='da65db00-054e-419d-9988-24d97953ca1e';
DELETE FROM lesson_blocks WHERE lesson_id='da65db00-054e-419d-9988-24d97953ca1e';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['In sequential conveyances the earlier (senior) deed takes the full measure of its description; the later (junior) deed takes only the remainder.','A grantor cannot convey land already conveyed to a senior grantee.','Sequential conveyances -> senior/junior rights; simultaneous (plat) conveyances -> proportionate apportionment, no lot is senior.','Texas GLO patents create senior titles against which later carve-outs and subdivisions are junior.']::text[], learning_objectives=ARRAY['State the senior/junior rights doctrine and apply it to sequential conveyances.','Distinguish sequential conveyances (senior/junior governs) from simultaneous conveyances (apportionment governs).','Recognize how the Texas GLO patent system creates senior titles against which later subdivisions are junior.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='9fc9e9f1-25b9-4c57-b4f2-e6e3b3a4de29';
DELETE FROM lesson_blocks WHERE lesson_id='9fc9e9f1-25b9-4c57-b4f2-e6e3b3a4de29';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Dignity of calls (highest to lowest): natural monuments > artificial monuments > adjoinder > course (bearing) > distance > quantity/area.','The hierarchy is a rebuttable rule of construction that always yields to the parties'' intent and the footsteps of the original surveyor.','Stafford v. King (1867) is the seminal Texas authority for both the hierarchy and the footsteps doctrine.','Common defects include failure to close, ambiguous calls, missing basis of bearing, and gaps/overlaps with adjoiners.']::text[], learning_objectives=ARRAY['State the dignity-of-calls hierarchy and apply it to resolve conflicting calls in a description.','Explain that the hierarchy is a rule of construction subordinate to intent and to the footsteps of the original surveyor.','Identify common defects in descriptions and how each is treated in retracement.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='42792d8e-0f3a-46d9-95c4-2add696124cf';
DELETE FROM lesson_blocks WHERE lesson_id='42792d8e-0f3a-46d9-95c4-2add696124cf';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Write the description in order with explicit ties, a stated basis of bearing, and documented monuments; it must close.','Linear misclosure = hypot(sum of latitudes, sum of departures); precision = perimeter / misclosure, expressed as 1:N.','Only an RPLS (or LSLS for state land) may prepare and seal a metes-and-bounds description; Occupations Code Ch. 1071 governs licensure and sealing.','Standards live in 22 TAC Ch. 138 (Subchapter E), not the repealed Ch. 663.']::text[], learning_objectives=ARRAY['Assemble a complete, closed metes-and-bounds description meeting 22 TAC Sec. 138.91 requirements.','Verify closure using linear misclosure and report precision per 22 TAC Sec. 138.83.','Explain who may seal a description and the role of the RPLS under Occupations Code Ch. 1071.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='1112f7a8-b60d-43db-aac0-c02cc1ce39cf';
DELETE FROM lesson_blocks WHERE lesson_id='1112f7a8-b60d-43db-aac0-c02cc1ce39cf';
  'eeee1450-0000-0000-0000-000000000001', 'Bearing to azimuth and back-azimuth', 'Bearing to azimuth and back-azimuth', 'Metes and Bounds — Directions', 'Bearings and azimuths', 'numeric_input', 'easy', 'A course has the quadrant bearing S {{ang:f0}} deg E. Express its forward azimuth (clockwise from north, in degrees), then report its BACK-azimuth in degrees.', '(180 - ang) + 180', '{"decimals":0,"unit":"deg","tolerance":0.5}', '[{"name":"ang","type":"integer","min":10,"max":80}]'::jsonb, '[{"name":"fwdAz","formula":"180 - ang"}]'::jsonb, '[{"step_number":1,"title":"Forward azimuth (SE quadrant)","formula":"180 - bearing angle","calculation_template":"180 - {{ang:f0}} = {{fwdAz:f0}} deg"},{"step_number":2,"title":"Back-azimuth","formula":"azimuth + 180 (since < 180)","result_template":"{{fwdAz:f0}} + 180 = {{_answer}} deg"}]'::jsonb, '{"method":"none"}'::jsonb, 'S {{ang:f0}} deg E is in the SE quadrant, so forward azimuth = 180 - {{ang:f0}} = {{fwdAz:f0}} deg. Since that is below 180 deg, the back-azimuth = {{fwdAz:f0}} + 180 = {{_answer}} deg.', 'c100000e-0000-0000-0000-00000000000e', ARRAY['buildout','module-14','practice']::text[], true, 'buildout:m14');
  'eeee1450-0000-0000-0000-000000000002', 'Latitude and departure of a course', 'Latitude and departure of a course', 'Metes and Bounds — Course geometry', 'Latitude and departure', 'numeric_input', 'medium', 'A course runs N {{ang:f0}} deg E for a distance of {{dist:f2}} ft. Compute the DEPARTURE (east-west component) of this course in feet.', 'dist*sin(toRad(ang))', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"ang","type":"integer","min":15,"max":75},{"name":"dist","type":"float","min":150,"max":600,"decimals":2}]'::jsonb, '[{"name":"lat","formula":"dist*cos(toRad(ang))"}]'::jsonb, '[{"step_number":1,"title":"Departure formula","formula":"Dep = d sin(alpha)","calculation_template":"{{dist:f2}} x sin({{ang:f0}} deg)"},{"step_number":2,"title":"Compute","result_template":"Departure = {{_answer}} ft (east, positive)"}]'::jsonb, '{"method":"none"}'::jsonb, 'Departure = d sin(alpha) = {{dist:f2}} x sin({{ang:f0}} deg) = {{_answer}} ft. (The latitude, d cos(alpha), would be {{lat:f2}} ft north.)', 'c100000e-0000-0000-0000-00000000000e', ARRAY['buildout','module-14','practice']::text[], true, 'buildout:m14');
  'eeee1450-0000-0000-0000-000000000003', 'Linear misclosure of a traverse', 'Linear misclosure of a traverse', 'Metes and Bounds — Closure', 'Misclosure', 'numeric_input', 'medium', 'After summing all courses of a closed-loop traverse, the latitudes total {{sumLat:f3}} ft and the departures total {{sumDep:f3}} ft. Compute the LINEAR MISCLOSURE (ft).', 'hypot(sumLat, sumDep)', '{"decimals":3,"unit":"ft","tolerance":0.002}', '[{"name":"sumLat","type":"float","min":-0.2,"max":0.2,"decimals":3},{"name":"sumDep","type":"float","min":-0.2,"max":0.2,"decimals":3}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Misclosure formula","formula":"sqrt(sumLat^2 + sumDep^2)","calculation_template":"sqrt(({{sumLat:f3}})^2 + ({{sumDep:f3}})^2)"},{"step_number":2,"title":"Compute","result_template":"Linear misclosure = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Linear misclosure is the hypotenuse of the latitude and departure misclosures: hypot({{sumLat:f3}}, {{sumDep:f3}}) = {{_answer}} ft.', 'c100000e-0000-0000-0000-00000000000e', ARRAY['buildout','module-14','practice']::text[], true, 'buildout:m14');
  'eeee1450-0000-0000-0000-000000000004', 'Parcel area in acres from square feet', 'Parcel area in acres from square feet', 'Metes and Bounds — Area', 'Area conversion', 'numeric_input', 'easy', 'A rectangular parcel measures {{a:f2}} ft by {{b:f2}} ft. Compute its area in ACRES (1 acre = 43,560 sq ft).', '(a*b)/43560', '{"decimals":3,"unit":"acres","tolerance":0.005}', '[{"name":"a","type":"float","min":120,"max":400,"decimals":2},{"name":"b","type":"float","min":150,"max":500,"decimals":2}]'::jsonb, '[{"name":"sf","formula":"a*b"}]'::jsonb, '[{"step_number":1,"title":"Area in square feet","formula":"length x width","calculation_template":"{{a:f2}} x {{b:f2}} = {{sf:f2}} sq ft"},{"step_number":2,"title":"Convert to acres","formula":"sq ft / 43560","result_template":"{{sf:f2}} / 43560 = {{_answer}} acres"}]'::jsonb, '{"method":"none"}'::jsonb, 'Area = {{a:f2}} x {{b:f2}} = {{sf:f2}} sq ft; dividing by 43,560 sq ft/acre gives {{_answer}} acres.', 'c100000e-0000-0000-0000-00000000000e', ARRAY['buildout','module-14','practice']::text[], true, 'buildout:m14');
COMMIT;
