INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1460-0000-0000-0000-000000000001', 'A course has the quadrant bearing S {{ang:f0}} deg E. Express its forward azimuth (clockwise from north, in degrees), then report its BACK-azimuth in degrees.', 'numeric_input', '[]'::jsonb, '0', 'S {{ang:f0}} deg E is in the SE quadrant, so forward azimuth = 180 - {{ang:f0}} = {{fwdAz:f0}} deg. Since that is below 180 deg, the back-azimuth = {{fwdAz:f0}} + 180 = {{_answer}} deg.', 'easy', 'c100000e-0000-0000-0000-00000000000e', NULL, ARRAY['buildout','module-14','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1450-0000-0000-0000-000000000001', 0.5);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1460-0000-0000-0000-000000000002', 'A course runs N {{ang:f0}} deg E for a distance of {{dist:f2}} ft. Compute the DEPARTURE (east-west component) of this course in feet.', 'numeric_input', '[]'::jsonb, '0', 'Departure = d sin(alpha) = {{dist:f2}} x sin({{ang:f0}} deg) = {{_answer}} ft. (The latitude, d cos(alpha), would be {{lat:f2}} ft north.)', 'medium', 'c100000e-0000-0000-0000-00000000000e', NULL, ARRAY['buildout','module-14','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1450-0000-0000-0000-000000000002', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1460-0000-0000-0000-000000000003', 'After summing all courses of a closed-loop traverse, the latitudes total {{sumLat:f3}} ft and the departures total {{sumDep:f3}} ft. Compute the LINEAR MISCLOSURE (ft).', 'numeric_input', '[]'::jsonb, '0', 'Linear misclosure is the hypotenuse of the latitude and departure misclosures: hypot({{sumLat:f3}}, {{sumDep:f3}}) = {{_answer}} ft.', 'medium', 'c100000e-0000-0000-0000-00000000000e', NULL, ARRAY['buildout','module-14','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1450-0000-0000-0000-000000000003', 0.002);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1460-0000-0000-0000-000000000004', 'A rectangular parcel measures {{a:f2}} ft by {{b:f2}} ft. Compute its area in ACRES (1 acre = 43,560 sq ft).', 'numeric_input', '[]'::jsonb, '0', 'Area = {{a:f2}} x {{b:f2}} = {{sf:f2}} sq ft; dividing by 43,560 sq ft/acre gives {{_answer}} acres.', 'easy', 'c100000e-0000-0000-0000-00000000000e', NULL, ARRAY['buildout','module-14','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1450-0000-0000-0000-000000000004', 0.005);
